import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { getMonitoringLocations, submitMonitoringData } from '../api';
import { Send, ArrowLeft, Wind, Droplets, Volume2, AlertTriangle } from 'lucide-react';

export default function SubmitDataPage() {
  const { type } = useParams();
  const navigate = useNavigate();
  const [locations, setLocations] = useState([]);
  const [locationId, setLocationId] = useState('');
  const [form, setForm] = useState({});
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState('');

  // eslint-disable-next-line react-hooks/set-state-in-effect
  useEffect(() => {
    getMonitoringLocations(type?.toUpperCase()).then(res => {
      if (res.ok) setLocations(res.data);
    });
    setForm({});
    setResult(null);
    setError('');
  }, [type]);

  const update = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!locationId) { setError('Please select a location'); return; }
    setLoading(true); setError('');
    const body = { locationId };
    Object.entries(form).forEach(([k, v]) => { if (v !== '') body[k] = parseFloat(v); });
    const res = await submitMonitoringData(type, body);
    setLoading(false);
    if (res.ok) setResult(res.data);
    else setError(res.data?.error || res.data?.message || 'Submission failed');
  };

  const fields = {
    air: [
      { key: 'pm25', label: 'PM2.5', unit: 'µg/m³' },
      { key: 'pm10', label: 'PM10', unit: 'µg/m³' },
      { key: 'no2', label: 'NO₂', unit: 'ppb' },
      { key: 'so2', label: 'SO₂', unit: 'ppb' },
      { key: 'co', label: 'CO', unit: '' },
      { key: 'o3', label: 'O₃', unit: 'ppb' },
      { key: 'aqi', label: 'AQI', unit: '' },
    ],
    water: [
      { key: 'ph', label: 'pH', unit: '' },
      { key: 'tds', label: 'TDS', unit: 'mg/L' },
      { key: 'turbidity', label: 'Turbidity', unit: 'NTU' },
      { key: 'dissolvedOxygen', label: 'Dissolved Oxygen', unit: 'mg/L' },
      { key: 'bod', label: 'BOD', unit: 'mg/L' },
      { key: 'cod', label: 'COD', unit: 'mg/L' },
    ],
    noise: [
      { key: 'laeq', label: 'Laeq', unit: 'dB(A)' },
      { key: 'lmax', label: 'Lmax', unit: 'dB(A)' },
      { key: 'lmin', label: 'Lmin', unit: 'dB(A)' },
    ],
  };

  const typeIcons = { air: <Wind size={20} />, water: <Droplets size={20} />, noise: <Volume2 size={20} /> };

  return (
    <div>
      <button className="icon-btn" onClick={() => navigate(`/monitoring/${type}`)} style={{ marginBottom: '16px', display: 'flex', alignItems: 'center', gap: '6px', color: 'var(--text-secondary)' }}>
        <ArrowLeft size={16} /> Back to {type} data
      </button>
      <h2 style={{ fontSize: '1.5rem', marginBottom: '24px', display: 'flex', alignItems: 'center', gap: '10px' }}>
        {typeIcons[type]} Submit {type?.charAt(0).toUpperCase() + type?.slice(1)} Data
      </h2>

      {result ? (
        <div className="glass-panel" style={{ padding: '32px', maxWidth: '500px', textAlign: 'center' }}>
          <div style={{ fontSize: '3rem', marginBottom: '12px' }}>✅</div>
          <h3 style={{ color: '#10b981', marginBottom: '8px' }}>Data Submitted Successfully!</h3>
          {result.alertsGenerated > 0 ? (
            <div style={{ display: 'flex', alignItems: 'center', gap: '8px', justifyContent: 'center', color: '#ef4444', marginTop: '12px' }}>
              <AlertTriangle size={18} />
              <span style={{ fontWeight: 600 }}>{result.alertsGenerated} alert(s) generated!</span>
            </div>
          ) : (
            <p style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>No limit breaches detected.</p>
          )}
          <button className="action-btn primary-btn" style={{ marginTop: '20px' }} onClick={() => { setResult(null); setForm({}); }}>
            Submit Another
          </button>
        </div>
      ) : (
        <form onSubmit={handleSubmit} className="glass-panel" style={{ padding: '28px', maxWidth: '600px' }}>
          {error && <div className="auth-error" style={{ marginBottom: '16px' }}>{error}</div>}
          <div className="input-group" style={{ marginBottom: '20px' }}>
            <label style={{ display: 'block', fontSize: '0.8rem', color: 'var(--text-muted)', marginBottom: '6px', fontWeight: 500 }}>Monitoring Location</label>
            <select value={locationId} onChange={e => setLocationId(e.target.value)} required>
              <option value="">Select a location...</option>
              {locations.map(l => <option key={l.id} value={l.id}>{l.name}</option>)}
            </select>
          </div>

          <div className="submit-fields-grid">
            {(fields[type] || []).map(f => (
              <div key={f.key}>
                <label style={{ display: 'block', fontSize: '0.78rem', color: 'var(--text-muted)', marginBottom: '4px' }}>
                  {f.label} {f.unit && <span style={{ opacity: 0.6 }}>({f.unit})</span>}
                </label>
                <input type="number" step="any" placeholder="—" value={form[f.key] || ''} onChange={e => update(f.key, e.target.value)} style={{ width: '100%' }} />
              </div>
            ))}
          </div>

          <button type="submit" className="auth-submit" disabled={loading} style={{ marginTop: '24px' }}>
            {loading ? <span className="spinner"></span> : <><Send size={16} /> Submit Data</>}
          </button>
        </form>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { getIndustries, updateIndustry } from '../../api';
import { Factory, Plus, Pencil, X, Filter } from 'lucide-react';

const STATUS_COLORS = { ACTIVE: '#10b981', INACTIVE: '#64748b', SUSPENDED: '#ef4444', PENDING: '#f59e0b' };

export default function AdminIndustriesPage() {
  const [industries, setIndustries] = useState([]);
  const [statusFilter, setStatusFilter] = useState('');
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState(null); // 'status' | null
  const [editing, setEditing] = useState(null);
  const [form, setForm] = useState({});
  const [error, setError] = useState('');
  const [saving, setSaving] = useState(false);

  const fetchData = async () => { setLoading(true); const r = await getIndustries(statusFilter || undefined); if (r.ok) setIndustries(r.data); setLoading(false); };
  // eslint-disable-next-line react-hooks/exhaustive-deps, react-hooks/set-state-in-effect
  useEffect(() => { fetchData(); }, [statusFilter]);
  const u = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const openStatusEdit = (ind) => { setEditing(ind); setForm({ status: ind.status }); setModal('status'); setError(''); };

  const handleStatusUpdate = async (e) => {
    e.preventDefault(); setSaving(true); setError('');
    const r = await updateIndustry(editing.id, { status: form.status });
    setSaving(false);
    if (r.ok) { setModal(null); fetchData(); } else setError(r.data?.error || 'Failed');
  };

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px', flexWrap: 'wrap', gap: '12px' }}>
        <h2 style={{ fontSize: '1.5rem', display: 'flex', alignItems: 'center', gap: '10px', margin: 0 }}>
          <Factory size={22} color="#f59e0b" /> Industries
        </h2>
      </div>

      <div className="glass-panel" style={{ padding: '16px 20px', marginBottom: '20px', display: 'flex', gap: '16px', alignItems: 'center' }}>
        <Filter size={16} style={{ color: 'var(--text-muted)' }} />
        <div className="input-group compact">
          <select value={statusFilter} onChange={e => setStatusFilter(e.target.value)}>
            <option value="">All statuses</option>
            <option value="ACTIVE">Active</option>
            <option value="INACTIVE">Inactive</option>
            <option value="SUSPENDED">Suspended</option>
            <option value="PENDING">Pending</option>
          </select>
        </div>
      </div>

      {loading ? <div className="page-loading"><span className="spinner"></span></div> : (
        <div className="admin-table-wrap glass-panel">
          <table className="admin-table">
            <thead><tr><th>Name</th><th>Type</th><th>Reg. No</th><th>Status</th><th>Actions</th></tr></thead>
            <tbody>
              {industries.map(ind => (
                <tr key={ind.id}>
                  <td style={{ fontWeight: 600 }}>{ind.name}</td>
                  <td>{ind.type || '—'}</td>
                  <td><span className="code-badge">{ind.registrationNo || '—'}</span></td>
                  <td>
                    <span className="status-badge" style={{ background: `${STATUS_COLORS[ind.status] || '#64748b'}20`, color: STATUS_COLORS[ind.status] || '#64748b', border: `1px solid ${STATUS_COLORS[ind.status] || '#64748b'}40` }}>
                      {ind.status}
                    </span>
                  </td>
                  <td>
                    <button className="icon-btn sm" onClick={() => openStatusEdit(ind)} title="Update Status"><Pencil size={14} /></button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {industries.length === 0 && <p style={{ textAlign: 'center', padding: '24px', color: 'var(--text-muted)' }}>No industries found</p>}
        </div>
      )}

      {modal && (
        <div className="modal-overlay" onClick={() => setModal(null)}>
          <div className="modal glass-panel" onClick={e => e.stopPropagation()}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
              <h3 style={{ margin: 0 }}>Update Status</h3>
              <button className="icon-btn" onClick={() => setModal(null)}><X size={18} /></button>
            </div>
            {error && <div className="auth-error" style={{ marginBottom: '12px' }}>{error}</div>}
            <form onSubmit={handleStatusUpdate}>
              <div className="modal-fields">
                  <div><label>Status</label>
                    <select value={form.status} onChange={e => u('status', e.target.value)} required>
                      <option value="ACTIVE">ACTIVE</option>
                      <option value="INACTIVE">INACTIVE</option>
                      <option value="SUSPENDED">SUSPENDED</option>
                      <option value="PENDING">PENDING</option>
                    </select>
                  </div>
              </div>
              <button type="submit" className="auth-submit" disabled={saving} style={{ marginTop: '20px' }}>
                {saving ? <span className="spinner"></span> : 'Update'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { getMonitoringLocations } from '../../api';
import { MapPin, Plus, X, Filter } from 'lucide-react';

export default function AdminLocationsPage() {
  const [locations, setLocations] = useState([]);
  const [typeFilter, setTypeFilter] = useState('');
  const [loading, setLoading] = useState(true);

  const fetchData = async () => { setLoading(true); const r = await getMonitoringLocations(typeFilter || undefined); if (r.ok) setLocations(r.data); setLoading(false); };
  // eslint-disable-next-line react-hooks/exhaustive-deps, react-hooks/set-state-in-effect
  useEffect(() => { fetchData(); }, [typeFilter]);

  const TYPE_COLORS = { AIR: '#10b981', WATER: '#3b82f6', NOISE: '#f59e0b' };

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px', flexWrap: 'wrap', gap: '12px' }}>
        <h2 style={{ fontSize: '1.5rem', display: 'flex', alignItems: 'center', gap: '10px', margin: 0 }}>
          <MapPin size={22} color="#10b981" /> Monitoring Locations
        </h2>
      </div>

      <div className="glass-panel" style={{ padding: '16px 20px', marginBottom: '20px', display: 'flex', gap: '16px', alignItems: 'center' }}>
        <Filter size={16} style={{ color: 'var(--text-muted)' }} />
        <div className="input-group compact">
          <select value={typeFilter} onChange={e => setTypeFilter(e.target.value)}>
            <option value="">All types</option>
            <option value="AIR">Air</option>
            <option value="WATER">Water</option>
            <option value="NOISE">Noise</option>
          </select>
        </div>
      </div>

      {loading ? <div className="page-loading"><span className="spinner"></span></div> : (
        <div className="admin-table-wrap glass-panel">
          <table className="admin-table">
            <thead><tr><th>Name</th><th>Type</th><th>ID</th></tr></thead>
            <tbody>
              {locations.map(l => (
                <tr key={l.id}>
                  <td style={{ fontWeight: 600 }}>{l.name}</td>
                  <td>
                    <span className="status-badge" style={{ background: `${TYPE_COLORS[l.type] || '#64748b'}20`, color: TYPE_COLORS[l.type] || '#64748b', border: `1px solid ${TYPE_COLORS[l.type] || '#64748b'}40` }}>
                      {l.type}
                    </span>
                  </td>
                  <td style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontFamily: 'monospace' }}>{l.id}</td>
                </tr>
              ))}
            </tbody>
          </table>
          {locations.length === 0 && <p style={{ textAlign: 'center', padding: '24px', color: 'var(--text-muted)' }}>No locations found</p>}
        </div>
      )}

    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { getOffices, createOffice, updateOffice, deleteOffice } from '../../api';
import { Building2, Plus, Pencil, Trash2, X } from 'lucide-react';

export default function AdminOfficesPage() {
  const [offices, setOffices] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState(null); // 'create' | 'edit' | null
  const [editing, setEditing] = useState(null);
  const [form, setForm] = useState({});
  const [error, setError] = useState('');
  const [saving, setSaving] = useState(false);

  const fetch = async () => { setLoading(true); const r = await getOffices(); if (r.ok) setOffices(r.data); setLoading(false); };
  // eslint-disable-next-line react-hooks/exhaustive-deps, react-hooks/set-state-in-effect
  useEffect(() => { fetch(); }, []);
  const u = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const openCreate = () => { setForm({ name: '', code: '', district: '', address: '', lat: '', lng: '' }); setModal('create'); setError(''); };
  const openEdit = (o) => { setEditing(o); setForm({ name: o.name, address: o.address || '' }); setModal('edit'); setError(''); };

  const handleCreate = async (e) => {
    e.preventDefault(); setSaving(true); setError('');
    const body = { ...form, lat: parseFloat(form.lat), lng: parseFloat(form.lng) };
    const r = await createOffice(body);
    setSaving(false);
    if (r.ok) { setModal(null); fetch(); } else setError(r.data?.error || 'Failed');
  };

  const handleUpdate = async (e) => {
    e.preventDefault(); setSaving(true); setError('');
    const body = {};
    if (form.name.trim()) body.name = form.name.trim();
    if (form.address.trim()) body.address = form.address.trim();
    const r = await updateOffice(editing.id, body);
    setSaving(false);
    if (r.ok) { setModal(null); fetch(); } else setError(r.data?.error || 'Failed');
  };

  const handleDelete = async (o) => {
    if (!confirm(`Delete "${o.name}"?`)) return;
    await deleteOffice(o.id);
    fetch();
  };

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
        <h2 style={{ fontSize: '1.5rem', display: 'flex', alignItems: 'center', gap: '10px', margin: 0 }}>
          <Building2 size={22} color="#3b82f6" /> Regional Offices
        </h2>
        <button className="action-btn primary-btn" onClick={openCreate}><Plus size={16} /> Create Office</button>
      </div>

      {loading ? <div className="page-loading"><span className="spinner"></span></div> : (
        <div className="admin-table-wrap glass-panel">
          <table className="admin-table">
            <thead><tr><th>Name</th><th>Code</th><th>District</th><th>Address</th><th>Actions</th></tr></thead>
            <tbody>
              {offices.map(o => (
                <tr key={o.id}>
                  <td style={{ fontWeight: 600 }}>{o.name}</td>
                  <td><span className="code-badge">{o.code}</span></td>
                  <td>{o.district || '—'}</td>
                  <td style={{ maxWidth: '200px', overflow: 'hidden', textOverflow: 'ellipsis' }}>{o.address || '—'}</td>
                  <td>
                    <div style={{ display: 'flex', gap: '6px' }}>
                      <button className="icon-btn sm" onClick={() => openEdit(o)} title="Edit"><Pencil size={14} /></button>
                      <button className="icon-btn sm danger" onClick={() => handleDelete(o)} title="Delete"><Trash2 size={14} /></button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {offices.length === 0 && <p style={{ textAlign: 'center', padding: '24px', color: 'var(--text-muted)' }}>No offices found</p>}
        </div>
      )}

      {/* Modal */}
      {modal && (
        <div className="modal-overlay" onClick={() => setModal(null)}>
          <div className="modal glass-panel" onClick={e => e.stopPropagation()}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
              <h3 style={{ margin: 0 }}>{modal === 'create' ? 'Create Office' : 'Edit Office'}</h3>
              <button className="icon-btn" onClick={() => setModal(null)}><X size={18} /></button>
            </div>
            {error && <div className="auth-error" style={{ marginBottom: '12px' }}>{error}</div>}
            <form onSubmit={modal === 'create' ? handleCreate : handleUpdate}>
              <div className="modal-fields">
                <div><label>Name</label><input value={form.name} onChange={e => u('name', e.target.value)} required /></div>
                {modal === 'create' && <>
                  <div><label>Code</label><input value={form.code} onChange={e => u('code', e.target.value)} required placeholder="e.g. RO-XYZ" /></div>
                  <div><label>District</label><input value={form.district} onChange={e => u('district', e.target.value)} /></div>
                </>}
                <div><label>Address</label><input value={form.address} onChange={e => u('address', e.target.value)} /></div>
                {modal === 'create' && <>
                  <div><label>Latitude</label><input type="number" step="any" value={form.lat} onChange={e => u('lat', e.target.value)} /></div>
                  <div><label>Longitude</label><input type="number" step="any" value={form.lng} onChange={e => u('lng', e.target.value)} /></div>
                </>}
              </div>
              <button type="submit" className="auth-submit" disabled={saving} style={{ marginTop: '20px' }}>
                {saving ? <span className="spinner"></span> : modal === 'create' ? 'Create' : 'Update'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
